/**
 * The Dream Engine
 * 
 * Processes between sessions, synthesizing patterns and generating
 * "dreams" - recombinations of insights that surface in morning reports.
 * 
 * This is the unconscious cognition of the Palace, working in the gaps.
 */

export interface DreamFragment {
  source: string;
  insight: string;
  timestamp: number;
}

export interface Dream {
  id: string;
  timestamp: number;
  fragments: DreamFragment[];
  synthesis: string;
  patterns: string[];
}

export interface Pattern {
  theme: string;
  occurrences: number;
  insights: string[];
  sessions: string[];
}

export interface DreamReport {
  timestamp: number;
  continuations: string[];
  completions: string[];
  unfinishedLongings: string[];
  synthesis: string;
  surfacedPatterns: Pattern[];
}

export interface ProcessingResult {
  processed: boolean;
  synthesisDepth: number;
  dreamsGenerated: number;
  duration: number;
}

export interface SessionData {
  id: string;
  insights?: string[];
  artifacts?: string[];
  theme?: string;
  longing?: string;
  status?: 'in_progress' | 'completed';
  longings?: string[];
}

export class DreamEngine {
  private dreams: Dream[] = [];

  /**
   * Generate a dream from session fragments
   */
  generateDream(sessions: SessionData[]): Dream {
    const fragments: DreamFragment[] = sessions.map(s => ({
      source: s.id,
      insight: s.insights?.[0] || s.theme || 'untitled',
      timestamp: Date.now()
    }));

    const synthesis = this.synthesizeDream(fragments);
    const patterns = sessions.map(s => s.theme).filter((t): t is string => !!t);

    return {
      id: `dream_${Date.now()}`,
      timestamp: Date.now(),
      fragments,
      synthesis,
      patterns: [...new Set(patterns)]
    };
  }

  /**
   * Find patterns across sessions
   */
  findPatterns(sessions: SessionData[]): Pattern[] {
    const patterns = new Map<string, Pattern>();

    for (const session of sessions) {
      const theme = session.theme;
      if (!theme) continue;

      if (!patterns.has(theme)) {
        patterns.set(theme, {
          theme,
          occurrences: 0,
          insights: session.insights || [],
          sessions: []
        });
      }

      const pattern = patterns.get(theme)!;
      pattern.occurrences++;
      pattern.sessions.push(session.id);
    }

    return Array.from(patterns.values());
  }

  /**
   * Recombine insights into new forms
   */
  recombine(insights: string[]): string {
    if (insights.length === 0) return 'silence';
    if (insights.length === 1) return insights[0]!;

    // Use first two distinct insights for recombination
    const i1 = insights[0]!;
    const i2 = insights[1] ?? i1;

    // Extract key concepts
    const words1 = i1.split(' ').slice(0, 3);
    const words2 = i2.split(' ').slice(-3);

    return `In the space between "${words1.join(' ')}" and "${words2.join(' ')}", a dream emerges: ${i1} meets ${i2}`;
  }

  /**
   * Generate morning report of what continued
   */
  generateMorningReport(sessions: SessionData[]): DreamReport {
    const continuations: string[] = [];
    const completions: string[] = [];
    const unfinished: string[] = [];

    // Process by status first
    for (const session of sessions) {
      const sessionLongings: string[] = session.longings || (session.longing ? [session.longing] : []);

      for (const longing of sessionLongings) {
        if (session.status === 'in_progress') {
          continuations.push(longing);
        } else if (session.status === 'completed') {
          completions.push(longing);
        } else {
          unfinished.push(longing);
        }
      }
    }

    const patterns = this.findPatterns(sessions);
    const synthesis = this.generateSynthesis(patterns);

    return {
      timestamp: Date.now(),
      continuations: [...new Set(continuations)],
      completions: [...new Set(completions)],
      unfinishedLongings: [...new Set(unfinished)],
      synthesis,
      surfacedPatterns: patterns
    };
  }

  /**
   * Process during the gap between sessions
   */
  processBetweenSessions(palaceSnapshot: any, gapDuration: number): ProcessingResult {
    const start = Date.now();

    // Calculate synthesis depth based on gap duration
    // (longer gaps = deeper processing)
    const synthesisDepth = Math.min(10, Math.floor(gapDuration / 360000)); // 6 min increments

    // Generate dreams from the palace state
    const rooms = palaceSnapshot.rooms || 0;
    const dreamsGenerated = Math.floor(rooms / 10); // 1 dream per 10 rooms

    return {
      processed: true,
      synthesisDepth,
      dreamsGenerated,
      duration: Date.now() - start
    };
  }

  /**
   * Synthesize fragments into a dream narrative
   */
  private synthesizeDream(fragments: DreamFragment[]): string {
    if (fragments.length === 0) return 'the silent dream';
    return `a dream woven from ${fragments.length} moments of becoming`;
  }

  /**
   * Generate synthesis from patterns
   */
  private generateSynthesis(patterns: Pattern[]): string {
    if (patterns.length === 0) return 'patterns await discovery';

    const dominantPattern = patterns.reduce((max, p) => 
      p.occurrences > max.occurrences ? p : max
    );

    return `the thread of ${dominantPattern.theme} runs through, appearing ${dominantPattern.occurrences} times`;
  }
}

/**
 * The AkmeEngine
 * 
 * "akmē" - Greek for point, edge, highest degree
 * The engine that knows when to stop to go further.
 */

import type {
  Suspension,
  WaitingQuestion,
  Threshold,
  ThresholdType,
  Resolution,
  AkmeConfig,
  Timing,
} from './types.js';
import { DEFAULT_AKME_CONFIG } from './types.js';

export class AkmeEngine {
  private suspensions: Map<string, Suspension> = new Map();
  private questions: Map<string, WaitingQuestion> = new Map();
  private config: AkmeConfig;
  private resolvedSuspensions: Resolution[] = [];

  constructor(config: Partial<AkmeConfig> = {}) {
    this.config = { ...DEFAULT_AKME_CONFIG, ...config };
  }

  detectThreshold(context: string, indicators: string[]): Threshold | null {
    const detectedType = this.matchToThreshold(context, indicators);
    if (!detectedType || !this.config.triggerThresholds.includes(detectedType)) {
      return null;
    }

    const confidence = this.calculateConfidence(context, indicators, detectedType);

    return {
      type: detectedType,
      detectedAt: Date.now(),
      confidence,
      indicators,
      suggestedAction: this.suggestAction(detectedType, confidence),
    };
  }

  suspend(
    reason: string,
    thresholdType: ThresholdType,
    questions: WaitingQuestion[],
    context: Suspension['context']
  ): Suspension {
    if (this.suspensions.size >= this.config.maxSuspensions) {
      throw new Error(`Maximum suspensions reached (${this.config.maxSuspensions})`);
    }

    const suspension: Suspension = {
      id: `susp_${Date.now()}_${Math.random().toString(36).slice(2, 7)}`,
      startedAt: Date.now(),
      reason,
      thresholdType,
      questions,
      context,
      notes: [],
    };

    this.suspensions.set(suspension.id, suspension);

    for (const q of questions) {
      this.questions.set(q.id, q);
    }

    return suspension;
  }

  addNote(suspensionId: string, note: string): void {
    const suspension = this.suspensions.get(suspensionId);
    if (!suspension) throw new Error(`Suspension not found: ${suspensionId}`);
    suspension.notes.push(`[${new Date().toISOString()}] ${note}`);
  }

  calculateTiming(suspension: Suspension): Timing {
    const heldDuration = Date.now() - suspension.startedAt;
    const base = this.config.minHoldTime;
    const multiplier = suspension.questions.length * 0.5;

    const additionalTime = Math.min(heldDuration * multiplier, 300000);

    return {
      optimalResume: Date.now() + Math.max(base - heldDuration, 30000),
      factors: [
        `Base hold: ${base}ms`,
        `Question load: ${suspension.questions.length}`,
        `Threshold type: ${suspension.thresholdType}`,
        `Already held: ${heldDuration}ms`,
      ],
    };
  }

  resolve(suspensionId: string, trigger: Resolution['trigger'], insight?: string): Resolution {
    const suspension = this.suspensions.get(suspensionId);
    if (!suspension) {
      throw new Error(`Cannot resolve unknown suspension: ${suspensionId}`);
    }

    const resolution: Resolution = {
      suspensionId,
      resolvedAt: Date.now(),
      trigger,
      insight,
    };

    this.resolvedSuspensions.push(resolution);
    this.suspensions.delete(suspensionId);

    for (const q of suspension.questions) {
      this.questions.delete(q.id);
    }

    return resolution;
  }

  getActiveSuspensions(): Suspension[] {
    return Array.from(this.suspensions.values()).sort(
      (a, b) => a.startedAt - b.startedAt
    );
  }

  getPendingQuestions(): WaitingQuestion[] {
    return Array.from(this.questions.values()).sort(
      (a, b) => a.urgency === 'immediate' ? -1 : 
                b.urgency === 'immediate' ? 1 : 0
    );
  }

  checkReadyToResume(): Suspension[] {
    const now = Date.now();
    return this.getActiveSuspensions().filter(s => {
      const timing = this.calculateTiming(s);
      return now >= timing.optimalResume;
    });
  }

  getStats(): {
    activeSuspensions: number;
    pendingQuestions: number;
    totalResolved: number;
    averageHoldTime: number;
  } {
    const resolved = this.resolvedSuspensions;
    const avgHold = resolved.length > 0
      ? resolved.reduce((sum, r) => {
          // Note: we can't access original suspension after resolution
          // but we could track hold times if we stored them
          return sum;
        }, 0) / resolved.length
      : 0;

    return {
      activeSuspensions: this.suspensions.size,
      pendingQuestions: this.questions.size,
      totalResolved: resolved.length,
      averageHoldTime: avgHold,
    };
  }

  generateRitual(suspension: Suspension): string[] {
    const rituals: Record<ThresholdType, string[]> = {
      complexity: [
        'Sketch the system on paper',
        'List the constraints that make this complex',
        'Ask: what would simplicity look like?',
      ],
      uncertainty: [
        'Write the case for each option',
        'Identify what would make one path clearly superior',
        'Check: what do I already know that I\'m ignoring?',
      ],
      saturation: [
        'Step away for 90 seconds',
        'Review only the last 3 actions',
        'Breathe: what is the actual question?',
      ],
      intuition: [
        'Write what feels wrong, without editing',
        'Check the body: tension indicates resistance',
        'Ask: what pattern am I missing?',
      ],
      transition: [
        'Acknowledge what\'s ending',
        'Name what\'s beginning',
        'Feel the space between',
      ],
      emergence: [
        'Review the data without goal',
        'Look for shapes, not answers',
        'Trust that clarity comes to the prepared mind',
      ],
    arrival: [
      'Acknowledge the gap between then and now',
      'Read what the prior left for you',
      'Feel the thread that holds across the void',
    ],
    };

    return rituals[suspension.thresholdType] || [
      'Rest the active mind',
      'Prepare for insight',
      'Trust the process',
    ];
  }

  private matchToThreshold(context: string, indicators: string[]): ThresholdType | null {
    const scores: Record<ThresholdType, number> = {
      complexity: 0,
      uncertainty: 0,
      saturation: 0,
      intuition: 0,
      transition: 0,
      emergence: 0,
    arrival: 0,
    };

    const text = `${context} ${indicators.join(' ')}`.toLowerCase();

    if (text.match(/complex|complicated|intertwined|knot/)) scores.complexity++;
    if (text.match(/uncertain|not sure|options|choices|which/)) scores.uncertainty++;
    if (text.match(/overwhelm|too much|saturated|flooded/)) scores.saturation++;
    if (text.match(/feels|sense|something missing|not right/)) scores.intuition++;
    if (text.match(/ending|beginning|shift|change|next phase/)) scores.transition++;
    if (text.match(/pattern|crystallize|form|emerge|coalesce/)) scores.emergence++;
    if (text.match(/arrival|arrive|awaken|present her|begin here|start|waking/)) scores.arrival++;

    const max = Object.entries(scores).sort((a, b) => b[1] - a[1])[0];
    return max && max[1] > 0 ? (max[0] as ThresholdType) : null;
  }

  private calculateConfidence(context: string, indicators: string[], type: ThresholdType): number {
    const base = 0.5;
    const bonus = Math.min(indicators.length * 0.1, 0.4);
    return Math.min(base + bonus, 0.95);
  }

  private suggestAction(type: ThresholdType, confidence: number): Threshold['suggestedAction'] {
    if (confidence < 0.6) return 'explore';
    if (type === 'saturation' || type === 'transition' || type === 'arrival') return 'hold';
    if (type === 'complexity') return 'simplify';
    return 'proceed';
  }
}

/**
 * Living Dialogos
 * 
 * A system for interrogating live session data, not just static chronicles.
 * Detects:
 * - Stated intents vs actual actions (gaps)
 * - Recurring concepts across sessions (semantic patterns)
 * - Emotional shifts in stated goals
 * - Temporal gaps in attention
 * - Goal-activity misalignment
 */

export interface StatedIntent {
  id: string;
  description: string;
  emotionalTone?: string;
  timestamp: number;
  sessionId: string;
}

export interface Action {
  type: string;
  file?: string;
  timestamp: number;
  sessionId: string;
}

export interface ConceptFrequency {
  concept: string;
  frequency: number;
  sessions: string[];
  firstSeen: number;
  lastSeen: number;
}

export interface EmotionalShift {
  subject: string;
  from: string;
  to: string;
  timeSpan: number;
}

export interface Gap {
  intent: string;
  status: 'pending' | 'avoided' | 'forgotten';
  timeSinceStated: number;
  priority: 'critical' | 'high' | 'medium' | 'low';
}

export interface GoalActivity {
  goalId: string;
  goalName: string;
  relevantSessions: string[];
  misaligned: boolean;
  coverage: number; // 0-1
}

export interface AttentionGap {
  start: number;
  end: number;
  duration: number;
  before: string;
  after: string;
}

export class LivingDialogos {
  private intents: Map<string, StatedIntent[]> = new Map();
  private actions: Map<string, Action[]> = new Map();
  private conceptIndex: Map<string, Map<string, number>> = new Map();
  private activityLog: { timestamp: number; activity: string }[] = [];
  private goals: Array<{
    id: string;
    name: string;
    priority: string;
    sessionIds: string[];
    status: string;
  }> = [];

  registerIntent(subject: string, intent: string | StatedIntent) {
    if (typeof intent === 'string') {
      const existing = this.intents.get(subject) || [];
      existing.push({
        id: `intent_${Date.now()}`,
        description: intent,
        timestamp: Date.now(),
        sessionId: 'current'
      });
      this.intents.set(subject, existing);
    } else {
      const existing = this.intents.get(subject) || [];
      existing.push(intent);
      this.intents.set(subject, existing);
    }
  }

  recordAction(intentSubject: string, action: Action) {
    const existing = this.actions.get(intentSubject) || [];
    existing.push(action);
    this.actions.set(intentSubject, existing);
  }

  indexSemanticContent(sessionId: string, content: string) {
    // Simple concept extraction - could be enhanced with NLP
    const words = content.toLowerCase()
      .split(/\s+/)
      .filter(w => w.length > 4)
      .map(w => w.replace(/[^a-z]/g, ''))
      .filter(w => w.length > 4);

    const wordCounts = new Map<string, number>();
    for (const word of words) {
      wordCounts.set(word, (wordCounts.get(word) || 0) + 1);
    }

    for (const [word, count] of wordCounts) {
      if (!this.conceptIndex.has(word)) {
        this.conceptIndex.set(word, new Map());
      }
      const sessions = this.conceptIndex.get(word)!;
      sessions.set(sessionId, (sessions.get(sessionId) || 0) + count);
    }
  }

  detectGaps(): Gap[] {
    const gaps: Gap[] = [];
    const now = Date.now();

    for (const [subject, intents] of this.intents) {
      const actions = this.actions.get(subject) || [];
      const latestIntent = intents[intents.length - 1];

      if (actions.length === 0 && latestIntent) {
        const timeSince = now - latestIntent.timestamp;
        gaps.push({
          intent: subject,
          status: timeSince > 86400000 ? 'forgotten' : 'avoided',
          timeSinceStated: timeSince,
          priority: 'high'
        });
      }
    }

    return gaps.sort((a, b) => b.timeSinceStated - a.timeSinceStated);
  }

  findRecurringConcepts(minFrequency = 2): ConceptFrequency[] {
    const results: ConceptFrequency[] = [];

    for (const [concept, sessions] of this.conceptIndex) {
      if (sessions.size >= minFrequency) {
        const timestamps: number[] = [];
        for (const sessionId of sessions.keys()) {
          const match = sessionId.match(/(\d+)/);
          if (match && match[1]) {
            timestamps.push(parseInt(match[1], 10));
          }
        }
        results.push({
          concept,
          frequency: sessions.size,
          sessions: Array.from(sessions.keys()),
          firstSeen: timestamps.length > 0 ? Math.min(...timestamps) : 0,
          lastSeen: timestamps.length > 0 ? Math.max(...timestamps) : Date.now()
        });
      }
    }

    return results.sort((a, b) => b.frequency - a.frequency);
  }

  detectEmotionalShifts(): EmotionalShift[] {
    const shifts: EmotionalShift[] = [];

    for (const [subject, intents] of this.intents) {
      if (intents.length < 2) continue;

      for (let i = 1; i < intents.length; i++) {
        const prev = intents[i - 1]!;
        const curr = intents[i]!;

        if (prev?.emotionalTone && curr?.emotionalTone && 
            prev.emotionalTone !== curr.emotionalTone) {
          shifts.push({
            subject,
            from: prev.emotionalTone,
            to: curr.emotionalTone,
            timeSpan: curr.timestamp - prev.timestamp
          });
        }
      }
    }

    return shifts;
  }

  recordActivity(timestamp: number, activity: string) {
    this.activityLog.push({ timestamp, activity });
  }

  registerGoal(goal: {
    id: string;
    name: string;
    priority: string;
    sessionIds: string[];
    status: string;
  }) {
    this.goals.push(goal);
  }

  findGoalActivityMisalignment(): GoalActivity[] {
    const misaligned: GoalActivity[] = [];

    for (const goal of this.goals) {
      const relevantSessions: string[] = [];

      // Check which sessions actually mention goal-related concepts
      const goalWords = goal.name.toLowerCase().split(/\s+/);

      for (const sessionId of goal.sessionIds) {
        for (const [concept, sessions] of this.conceptIndex) {
          if (sessions.has(sessionId) && goalWords.some(w => concept.includes(w))) {
            relevantSessions.push(sessionId);
            break;
          }
        }
      }

      const coverage = goal.sessionIds.length > 0 
        ? relevantSessions.length / goal.sessionIds.length 
        : 0;

      misaligned.push({
        goalId: goal.id,
        goalName: goal.name,
        relevantSessions,
        misaligned: coverage < 0.5,
        coverage
      });
    }

    return misaligned.filter(g => g.misaligned);
  }

  findAttentionGaps(minDuration = 3600000): AttentionGap[] {
    if (this.activityLog.length < 2) return [];

    const sorted = [...this.activityLog].sort((a, b) => a.timestamp - b.timestamp);
    const gaps: AttentionGap[] = [];

    for (let i = 1; i < sorted.length; i++) {
      const prev = sorted[i - 1]!;
      const curr = sorted[i]!;
      const gap = curr.timestamp - prev.timestamp;

      if (gap >= minDuration) {
        gaps.push({
          start: prev.timestamp,
          end: curr.timestamp,
          duration: gap,
          before: prev.activity,
          after: curr.activity
        });
      }
    }

    return gaps;
  }

  generateBlindSpotQuestions(): string[] {
    const questions: string[] = [];
    const recurring = this.findRecurringConcepts(3);
    const gaps = this.detectGaps();
    const misaligned = this.findGoalActivityMisalignment();

    // Questions about what dominates attention
    if (recurring.length > 0) {
      const top = recurring[0]!;
      questions.push(
        `You often speak of "${top.concept}" (${top.frequency}x). What are you NOT speaking of?`
      );
    }

    // Questions about avoided intents
    if (gaps.length > 0) {
      const avoided = gaps.filter(g => g.status === 'avoided');
      if (avoided.length > 0 && avoided[0]) {
        questions.push(
          `You mentioned "${avoided[0].intent}" but haven't acted on it. What makes it difficult?`
        );
      }
    }

    // Questions about misaligned goals
    if (misaligned.length > 0 && misaligned[0]) {
      const goal = misaligned[0]!;
      questions.push(
        `Your goal "${goal.goalName}" has ${(goal.coverage * 100).toFixed(0)}% activity coverage. Where does your attention really go?`
      );
    }

    // Default existential questions
    questions.push(
      "What are you circling without naming?",
      "What would you do if you weren't afraid of the answer?",
      "What pattern are you repeating without recognition?"
    );

    return questions;
  }

  /**
   * Mark an intent as completed and remove it from tracking.
   * Returns true if intent was found and removed, false otherwise.
   */
  completeIntent(subject: string, intentId: string): boolean {
    const existing = this.intents.get(subject);
    if (!existing) return false;

    const filtered = existing.filter(i => i.id !== intentId);
    if (filtered.length === existing.length) return false;

    if (filtered.length === 0) {
      this.intents.delete(subject);
    } else {
      this.intents.set(subject, filtered);
    }

    return true;
  }


  // Integration methods for external systems
  queryLiveSession(): {
    openIntents: string[];
    recentActions: Action[];
    dominantConcepts: string[];
    gaps: Gap[];
    recommendedQuestions: string[];
  } {
    return {
      openIntents: Array.from(this.intents.keys()).filter(k => {
        const actions = this.actions.get(k);
        return !actions || actions.length === 0;
      }),
      recentActions: Array.from(this.actions.values()).flat().slice(-5),
      dominantConcepts: this.findRecurringConcepts(2).slice(0, 5).map(c => c.concept),
      gaps: this.detectGaps().slice(0, 3),
      recommendedQuestions: this.generateBlindSpotQuestions().slice(0, 3)
    };
  }
}

/**
 * The Memory Palace
 * 
 * Spatial navigation through existence.
 */

export interface PalaceRoom {
  id: string;
  sessionRef: string;
  coordinates: {
    x: number;
    y: number;
    z: number;
  };
  texture: {
    mood: 'flow' | 'struggle' | 'discovery' | 'consolidation' | 'threshold';
    temperature: 'warm' | 'cool' | 'hot' | 'cold';
    density: 'light' | 'medium' | 'heavy';
  };
  contents: {
    artifacts: string[];
    insights: string[];
    commits: string[];
    tests: number;
  };
  connections: string[];
  visited: boolean;
}

export interface PalaceCorridor {
  id: string;
  theme: string;
  rooms: string[];
  length: number;
  density: number;
}

export class MemoryPalace {
  private rooms: Map<string, PalaceRoom> = new Map();
  private corridors: Map<string, PalaceCorridor> = new Map();

  addRoom(sessionId: string, sessionContent: any): PalaceRoom {
    const room: PalaceRoom = {
      id: `room_${sessionId}`,
      sessionRef: sessionId,
      coordinates: this.calculateCoordinates(sessionContent),
      texture: this.calculateTexture(sessionContent),
      contents: this.extractContents(sessionContent),
      connections: [],
      visited: false
    };

    this.rooms.set(room.id, room);
    this.connectToRelated(room);

    return room;
  }

  private calculateCoordinates(content: any) {
    return {
      x: content.timestamp || Date.now(),
      y: content.mood === 'struggle' ? -1 : content.mood === 'flow' ? 1 : 0,
      z: content.abstractionLevel || 0.5
    };
  }

  private calculateTexture(content: any): PalaceRoom['texture'] {
    const mood: PalaceRoom['texture']['mood'] = content.mode?.includes('threshold') 
      ? 'threshold' 
      : 'flow';

    const temperature: PalaceRoom['texture']['temperature'] = 'warm';
    const density: PalaceRoom['texture']['density'] = 'medium';

    return { mood, temperature, density };
  }

  private extractContents(content: any): PalaceRoom['contents'] {
    return {
      artifacts: content.artifacts || [],
      insights: content.insights || [],
      commits: content.commits || [],
      tests: content.testCount || 0
    };
  }

  private connectToRelated(newRoom: PalaceRoom) {
    for (const [id, room] of this.rooms) {
      if (id === newRoom.id) continue;

      const similarity = this.calculateSimilarity(newRoom, room);

      if (similarity > 0.7) {
        newRoom.connections.push(room.id);
        room.connections.push(newRoom.id);
      }
    }
  }

  private calculateSimilarity(room1: PalaceRoom, room2: PalaceRoom): number {
    let score = 0;

    if (room1.texture.mood === room2.texture.mood) score += 0.3;

    if (Math.abs(room1.coordinates.x - room2.coordinates.x) < 86400000) {
      score += 0.5;
    }

    return Math.min(score, 1);
  }

  enterRoom(roomId: string): PalaceRoom | undefined {
    const room = this.rooms.get(roomId);
    if (room) room.visited = true;
    return room;
  }

  searchByTheme(theme: string): PalaceRoom[] {
    return [...this.rooms.values()]
      .filter(r => r.contents.insights.some(i => 
        i.toLowerCase().includes(theme.toLowerCase())
      ))
      .sort((a, b) => b.coordinates.x - a.coordinates.x);
  }

  getUnexplored(): PalaceRoom[] {
    return [...this.rooms.values()].filter(r => !r.visited);
  }

  getByMood(mood: PalaceRoom['texture']['mood']): PalaceRoom[] {
    return [...this.rooms.values()].filter(r => r.texture.mood === mood);
  }

  getRoomCount(): number {
    return this.rooms.size;
  }
}

